where not exists (
  select 1 from public.point_views p
  where lower(p.name)=lower(v.name)
    and abs(coalesce(p.latitude, 0) - v.latitude) < 0.0001
    and abs(coalesce(p.longitude, 0) - v.longitude) < 0.0001
);

